@register
class ExportExcelNode(BaseNode):
    type_id = 'ticimax.export_excel'
    category = "ticimax"
    display_name = 'Export Excel'
    description = 'Verileri Excel dosyasina export eder.'
    icon = 'box'
    color = '#0ea5e9'
    config_schema = {'type': 'object', 'properties': {'veri_tipi': {'type': 'string', 'title': 'veri_tipi'}, 'dosya_adi': {'type': 'string', 'title': 'dosya_adi', 'default': ''}, 'siparis_tarih_baslangic': {'type': 'string', 'title': 'siparis_tarih_baslangic', 'default': ''}, 'siparis_tarih_bitis': {'type': 'string', 'title': 'siparis_tarih_bitis', 'default': ''}, 'siparis_durumu': {'type': 'integer', 'title': 'siparis_durumu', 'default': -1}, 'urun_kategori_id': {'type': 'integer', 'title': 'urun_kategori_id', 'default': -1}, 'urun_marka_id': {'type': 'integer', 'title': 'urun_marka_id', 'default': -1}, 'urun_aktif': {'type': 'integer', 'title': 'urun_aktif', 'default': -1}, 'uye_id': {'type': 'integer', 'title': 'uye_id', 'default': -1}, 'kayit_sayisi': {'type': 'integer', 'title': 'kayit_sayisi', 'default': 500}}, 'required': ['veri_tipi']}

    async def execute(self, context: ExecutionContext, inputs: dict[str, Any], config: dict[str, Any]) -> dict[str, Any]:
        site = context.site
        if site is None:
            raise RuntimeError("Ticimax node requires a site on the workflow")
        alan_adi = site.domain
        uye_kodu = CryptoService.decrypt(site.uye_kodu_encrypted)

        def _get_client(a: str, u: str):
            return TicimaxService.get_client(site)

        veri_tipi = config.get('veri_tipi', None)
        dosya_adi = config.get('dosya_adi', '')
        siparis_tarih_baslangic = config.get('siparis_tarih_baslangic', '')
        siparis_tarih_bitis = config.get('siparis_tarih_bitis', '')
        siparis_durumu = config.get('siparis_durumu', -1)
        urun_kategori_id = config.get('urun_kategori_id', -1)
        urun_marka_id = config.get('urun_marka_id', -1)
        urun_aktif = config.get('urun_aktif', -1)
        uye_id = config.get('uye_id', -1)
        kayit_sayisi = config.get('kayit_sayisi', 500)

        def _run():
            client = _get_client(alan_adi, uye_kodu)
            timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")

            if not dosya_adi:
                dosya_adi = os.path.join(
                    tempfile.gettempdir(), f"ticimax_{veri_tipi}_{timestamp}.xlsx"
                )
            elif not os.path.isabs(dosya_adi):
                dosya_adi = os.path.join(tempfile.gettempdir(), dosya_adi)

            if veri_tipi == "siparis":
                filtre_args = {
                    "SiparisID": -1,
                    "SiparisDurumu": siparis_durumu,
                    "OdemeDurumu": -1,
                }
                if siparis_tarih_baslangic:
                    filtre_args["SiparisTarihiBas"] = siparis_tarih_baslangic
                if siparis_tarih_bitis:
                    filtre_args["SiparisTarihiSon"] = siparis_tarih_bitis
                filtre = client.siparis_factory.WebSiparisFiltre(**filtre_args)
                sayfalama = client.siparis_factory.WebSiparisSayfalama(
                    BaslangicIndex=0, KayitSayisi=kayit_sayisi,
                    SiralamaDegeri="id", SiralamaYonu="Desc",
                )
                data = client.siparis.SelectSiparis(
                    UyeKodu=client.uye_kodu, f=filtre, s=sayfalama
                )

            elif veri_tipi == "urun":
                filtre = client.urun_factory.UrunFiltre(
                    UrunKartiID=-1, KategoriID=urun_kategori_id,
                    MarkaID=urun_marka_id, Aktif=urun_aktif,
                )
                sayfalama = client.urun_factory.UrunSayfalama(
                    BaslangicIndex=0, KayitSayisi=kayit_sayisi,
                    SiralamaDegeri="id", SiralamaYonu="Desc",
                )
                data = client.urun.SelectUrun(
                    UyeKodu=client.uye_kodu, f=filtre, s=sayfalama
                )

            elif veri_tipi == "uye":
                filtre = client.uye_factory.UyeFiltre(UyeID=uye_id)
                sayfalama = client.uye_factory.UyeSayfalama(
                    SayfaNo=1, KayitSayisi=kayit_sayisi,
                )
                data = client.uye.SelectUyeler(
                    UyeKodu=client.uye_kodu, filtre=filtre, sayfalama=sayfalama
                )

            elif veri_tipi == "kategori":
                data = client.urun.SelectKategori(
                    UyeKodu=client.uye_kodu, kategoriID=-1, dil=""
                )

            elif veri_tipi == "kargo":
                data = client.custom.SelectKargoFirmalari(UyeKodu=client.uye_kodu)

            else:
                return f"Bilinmeyen veri_tipi: {veri_tipi}. Gecerli: siparis, urun, uye, kategori, kargo"

            export_to_excel(data, dosya_adi)
            return f"Excel dosyasi olusturuldu: {dosya_adi}"

        # Run the synchronous SOAP call in a worker thread so we
        # do not block the FastAPI event loop (zeep is sync).
        return {"result": await asyncio.to_thread(_run)}


