    type_id = 'ticimax.save_magaza'
    category = "ticimax"
    display_name = 'Save Magaza'
    description = 'Magaza bilgilerini kaydeder veya gunceller.'
    icon = 'save'
    color = '#10b981'
    config_schema = {'type': 'object', 'properties': {'magaza_listesi': {'type': 'array', 'items': {'type': 'object'}, 'title': 'magaza_listesi'}}, 'required': ['magaza_listesi']}

    async def execute(self, context: ExecutionContext, inputs: dict[str, Any], config: dict[str, Any]) -> dict[str, Any]:
        site = context.site
        if site is None:
            raise RuntimeError("Ticimax node requires a site on the workflow")
        alan_adi = site.domain
        uye_kodu = CryptoService.decrypt(site.uye_kodu_encrypted)

        def _get_client(a: str, u: str):
            return TicimaxService.get_client(site)

        magaza_listesi = config.get('magaza_listesi', None)

        def _run():
            client = _get_client(alan_adi, uye_kodu)
            magaza_list = []
            ayar_fields = {}
            for d in magaza_listesi:
                magaza = client.siparis_factory.WebMagaza(
                    **{k: v for k, v in d.items() if k not in ("ayar",)}
                )
                magaza_list.append(magaza)
                for k in d:
                    guncelle_key = f"{k}Guncelle"
                    ayar_fields[guncelle_key] = True
            ayar = client.siparis_factory.WebMagazaAyar(**ayar_fields)
            result = client.siparis.SaveMagaza(
                UyeKodu=client.uye_kodu, magazaList=magaza_list, ayar=ayar
            )
            return _serialize(result)

        # Run the synchronous SOAP call in a worker thread so we
        # do not block the FastAPI event loop (zeep is sync).
        return {"result": await asyncio.to_thread(_run)}


